const alert = $input.item.json;
const body = alert.body || alert;
const alertData = body.alert || body;

const rule = alertData.rule || {};
const agent = alertData.agent || {};
const data = alertData.data || {};

const severityLevel = parseInt(rule.level) || 0;
let priority = 1;
if (severityLevel >= 12) priority = 3;
else if (severityLevel >= 7) priority = 2;

// Elevate authentication failures to P2 for SOC visibility
if (rule.description?.toLowerCase().includes('authentication failure')) {
  priority = 2;
}

return {
  json: {
    skip: false,
    rule_id: rule.id,
    rule_description: rule.description,
    severity: severityLevel,
    priority: priority,
    source_ip: data.srcip || data.src_ip || 'N/A',
    dest_ip: data.dstip || data.dst_ip || 'N/A',
    hostname: agent.name || 'unknown',
    agent_id: agent.id || 'N/A',
    full_log: alertData.full_log || '',
    timestamp: alertData.timestamp || alert.timestamp || new Date().toISOString(),
    mitre_tactics: (rule.mitre?.tactic || []).join(', '),
    mitre_ids: (rule.mitre?.id || []).join(', '),
    groups: (rule.groups || []).join(', ')
  }
};

const d = $input.item.json;
if (d.skip) return [];

const prompt = `You are a Tier 2 SOC Analyst. Summarize this security alert in a concise, professional briefing for an on-call engineer.

Alert Details:
- Rule: ${d.rule_description || 'N/A'}
- Rule ID: ${d.rule_id || 'N/A'}
- Severity: ${d.severity}/15
- Source IP: ${d.source_ip}
- Destination IP: ${d.dest_ip}
- Affected Host: ${d.hostname}
- Timestamp: ${d.timestamp}
- MITRE ATT&CK: ${d.mitre_tactics || 'N/A'}
- Groups: ${d.groups || 'N/A'}
- Full Log: ${d.full_log?.substring(0, 800) || 'N/A'}

TASK:
1. Provide a professional summary.
2. Identify any CVEs associated with this type of activity or rule.
3. Provide an explanation of those CVEs and suggested mitigations.

Provide a JSON response with:
{
  "summary": "Executive Summary (2-3 sentences)",
  "cve_list": ["CVE-YYYY-XXXXX"],
  "cve_details": "Explanation of identified CVEs and their mitigations",
  "iocs": ["array of IPs, hashes, domains"],
  "immediate_actions": ["recommended actions if any"],
  "severity_assessment": "Assessment"
}

Format: Professional, clinical tone. No speculation. JSON only.`;

return { json: { prompt } };

const data = $input.item.json;
let summary = { 
  summary: 'No AI response', 
  cve_list: [], 
  cve_details: 'N/A', 
  iocs: [], 
  immediate_actions: [], 
  severity_assessment: 'Unknown' 
};

try {
  if (data.choices && data.choices[0]?.message?.content) {
    const text = data.choices[0].message.content;
    const match = text.match(/\{[\s\S]*\}/);
    if (match) summary = JSON.parse(match[0]);
  }
} catch (e) {
  summary.summary = 'Error parsing AI response: ' + e.message;
}

return { json: summary };
